sql:
SELECT COUNT(*) AS total_engagements
FROM user_engagements
WHERE campaign_id = 0;

SELECT user_id, campaign_id, engagement_type
FROM user_engagements
WHERE converted = 1;

SELECT conversion_rate 
FROM conversion_reports 
WHERE conversion_rate > 0.5 AND conversion_rate <= 0.7;

SELECT conversion_rate
FROM conversion_reports
WHERE campaign_id = 0;

SELECT campaign_id, conversion_rate
FROM conversion_reports
ORDER BY conversion_rate DESC;

SELECT user_id, user_name
FROM users
WHERE user_id NOT IN (SELECT user_id FROM user_roles WHERE role_id = 1);

SELECT COUNT(DISTINCT user_id) AS total_users
FROM user_engagements
WHERE converted = 1;

SELECT DISTINCT user_id 
FROM user_engagements 
WHERE converted = 1;

SELECT COUNT(campaign_id)
FROM campaign_audiences
WHERE audience_id = 1;

SELECT COUNT(DISTINCT user_id) 
FROM user_engagements 
WHERE converted = 1;

external_knowledge:
- Successful campaigns refer to those with a conversion rate of 10% or higher;
- The first quarter of 2022 is between January 1, 2022, and March 31, 2022;
- A high conversion rate means the ratio of total conversions to total engagements is >= 0.1.
